const axios = require('axios');
const title = $title;
const content = $content;

try {
  const auth = 'Basic ' + Buffer.from('YOUR_EMAIL:YOUR_ATLASSIAN_TOKEN').toString('base64');

  const response = await axios.post('https://srivardhan.atlassian.net/wiki/rest/api/content', {
    title: title,
    type: "page",
    space: { key: "SCRUM" },
    body: {
      storage: {
        value: `<div>${content}</div>`,
        representation: "storage"
      }
    }
  }, {
    headers: {
      'Authorization': auth,
      'Content-Type': 'application/json'
    }
  });

  return "SUCCESS: Confluence page created: " + response.data._links.base + response.data._links.webui;
} catch (error) {
  return "ERROR: " + (error.response ? JSON.stringify(error.response.data) : error.message);
}
